use std::collections::VecDeque;

/// RSI implementation with Wilder's smoothing for trading systems
pub struct RSI {
    period: usize,
    gains: VecDeque<f64>,
    losses: VecDeque<f64>,
    avg_gain: f64,
    avg_loss: f64,
    initialized: bool,
}

impl RSI {
    /// Create a new RSI instance with the specified period
    pub fn new(period: usize) -> Self {
        Self {
            period,
            gains: VecDeque::with_capacity(period),
            losses: VecDeque::with_capacity(period),
            avg_gain: 0.0,
            avg_loss: 0.0,
            initialized: false,
        }
    }

    /// Calculate RSI from a slice of price data
    /// Returns a vector of RSI values for each adjacent price pair
    pub fn calculate(&mut self, prices: &[f64]) -> Vec<f64> {
        if prices.len() < 2 {
            return vec![];
        }

        let mut rsi_values = Vec::with_capacity(prices.len());

        for window in prices.windows(2) {
            let delta = window[1] - window[0];

            // Track gains and losses using Wilder's method
            if delta > 0.0 {
                self.gains.push_back(delta);
                self.losses.push_back(0.0);
            } else {
                self.gains.push_back(0.0);
                self.losses.push_back(-delta);
            }

            // Maintain sliding window
            if self.gains.len() > self.period {
                self.gains.pop_front();
                self.losses.pop_front();
            }

            // Calculate RSI once we have enough data
            if self.gains.len() == self.period {
                if !self.initialized {
                    // Initial average using simple mean
                    self.avg_gain = self.gains.iter().sum::<f64>() / self.period as f64;
                    self.avg_loss = self.losses.iter().sum::<f64>() / self.period as f64;
                    self.initialized = true;
                } else {
                    // Wilder's smoothing: (prev_avg * (period-1) + current) / period
                    let last_gain = self.gains.back().unwrap_or(&0.0);
                    let last_loss = self.losses.back().unwrap_or(&0.0);

                    self.avg_gain = ((self.avg_gain * (self.period - 1) as f64) + last_gain) 
                                    / self.period as f64;
                    self.avg_loss = ((self.avg_loss * (self.period - 1) as f64) + last_loss) 
                                    / self.period as f64;
                }

                // Calculate RS and RSI
                let rs = if self.avg_loss > 0.0 {
                    self.avg_gain / self.avg_loss
                } else {
                    f64::INFINITY
                };

                let rsi = if rs.is_infinite() {
                    100.0
                } else {
                    100.0 - (100.0 / (1.0 + rs))
                };

                rsi_values.push(rsi);
            }
        }

        rsi_values
    }

    /// Reset the RSI state for a new data stream
    pub fn reset(&mut self) {
        self.gains.clear();
        self.losses.clear();
        self.avg_gain = 0.0;
        self.avg_loss = 0.0;
        self.initialized = false;
    }
}

