class RSI {
private:
    int period;
    std::deque<double> gains;
    std::deque<double> losses;
    double avg_gain;
    double avg_loss;
    bool initialized;

public:
    RSI(int period = 14) 
        : period(period), 
          avg_gain(0.0), 
          avg_loss(0.0), 
          initialized(false) {
        gains.reserve(period);
        losses.reserve(period);
    }

    std::vector<double> calculate(const std::vector<double>& prices) {
        if (prices.size() < 2) {
            return std::vector<double>();
        }

        std::vector<double> rsi_values;
        rsi_values.reserve(prices.size());

        for (size_t i = 1; i < prices.size(); ++i) {
            double delta = prices[i] - prices[i-1];

            if (delta > 0.0) {
                gains.push_back(delta);
                losses.push_back(0.0);
            } else {
                gains.push_back(0.0);
                losses.push_back(-delta);
            }

            if (gains.size() > static_cast<size_t>(period)) {
                gains.pop_front();
                losses.pop_front();
            }

            if (gains.size() == static_cast<size_t>(period)) {
                if (!initialized) {
                    avg_gain = std::accumulate(gains.begin(), gains.end(), 0.0) / period;
                    avg_loss = std::accumulate(losses.begin(), losses.end(), 0.0) / period;
                    initialized = true;
                } else {
                    double last_gain = gains.back();
                    double last_loss = losses.back();

                    avg_gain = ((avg_gain * (period - 1)) + last_gain) / period;
                    avg_loss = ((avg_loss * (period - 1)) + last_loss) / period;
                }

                double rs = (avg_loss > 0.0) ? (avg_gain / avg_loss) : std::numeric_limits<double>::infinity();
                double rsi = std::isinf(rs) ? 100.0 : 100.0 - (100.0 / (1.0 + rs));

                rsi_values.push_back(rsi);
            }
        }

        return rsi_values;
    }

    void reset() {
        gains.clear();
        losses.clear();
        avg_gain = 0.0;
        avg_loss = 0.0;
        initialized = false;
    }
};

import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;

public class RSI {
    private final int period;
    private final LinkedList<Double> gains;
    private final LinkedList<Double> losses;
    private double avgGain;
    private double avgLoss;
    private boolean initialized;

    public RSI(int period) {
        this.period = period;
        this.gains = new LinkedList<>();
        this.losses = new LinkedList<>();
        this.avgGain = 0.0;
        this.avgLoss = 0.0;
        this.initialized = false;
    }

    public RSI() {
        this(14);
    }

    public List<Double> calculate(double[] prices) {
        if (prices.length < 2) {
            return new ArrayList<>();
        }

        List<Double> rsiValues = new ArrayList<>(prices.length);

        for (int i = 1; i < prices.length; i++) {
            double delta = prices[i] - prices[i - 1];

            if (delta > 0.0) {
                gains.add(delta);
                losses.add(0.0);
            } else {
                gains.add(0.0);
                losses.add(-delta);
            }

            if (gains.size() > period) {
                gains.removeFirst();
                losses.removeFirst();
            }

            if (gains.size() == period) {
                if (!initialized) {
                    avgGain = gains.stream().mapToDouble(Double::doubleValue).sum() / period;
                    avgLoss = losses.stream().mapToDouble(Double::doubleValue).sum() / period;
                    initialized = true;
                } else {
                    double lastGain = gains.getLast();
                    double lastLoss = losses.getLast();

                    avgGain = ((avgGain * (period - 1)) + lastGain) / period;
                    avgLoss = ((avgLoss * (period - 1)) + lastLoss) / period;
                }

                double rs = (avgLoss > 0.0) ? (avgGain / avgLoss) : Double.POSITIVE_INFINITY;
                double rsi = Double.isInfinite(rs) ? 100.0 : 100.0 - (100.0 / (1.0 + rs));

                rsiValues.add(rsi);
            }
        }

        return rsiValues;
    }

    public void reset() {
        gains.clear();
        losses.clear();
        avgGain = 0.0;
        avgLoss = 0.0;
        initialized = false;
    }
}

