function calculateRSI(prices, period = 14) {
    if (!prices || prices.length < 2) {
        return [];
    }

    const rsiValues = [];
    const gains = [];
    const losses = [];
    let avgGain = 0;
    let avgLoss = 0;
    let initialized = false;

    for (let i = 1; i < prices.length; i++) {
        const delta = prices[i] - prices[i - 1];

        if (delta > 0) {
            gains.push(delta);
            losses.push(0);
        } else {
            gains.push(0);
            losses.push(-delta);
        }

        if (gains.length > period) {
            gains.shift();
            losses.shift();
        }

        if (gains.length === period) {
            if (!initialized) {
                avgGain = gains.reduce((a, b) => a + b, 0) / period;
                avgLoss = losses.reduce((a, b) => a + b, 0) / period;
                initialized = true;
            } else {
                const lastGain = gains[gains.length - 1];
                const lastLoss = losses[losses.length - 1];

                avgGain = ((avgGain * (period - 1)) + lastGain) / period;
                avgLoss = ((avgLoss * (period - 1)) + lastLoss) / period;
            }

            const rs = avgLoss > 0 ? (avgGain / avgLoss) : Infinity;
            const rsi = rs === Infinity ? 100 : 100 - (100 / (1 + rs));

            rsiValues.push(rsi);
        }
    }

    return rsiValues;
}

