/**
 * Type-safe RSI Implementation
 */

interface RSIOptions {
    period?: number;
    onUpdate?: (rsi: number, meta: RSIMetadata) => void;
}

interface RSIMetadata {
    avgGain: number;
    avgLoss: number;
    period: number;
    price: number;
    timestamp?: number;
}

interface RSICalculationResult {
    rsi: number | null;
    metadata: RSIMetadata;
}

class RSICalculator {
    private period: number;
    private gains: number[] = [];
    private losses: number[] = [];
    private avgGain: number = 0;
    private avgLoss: number = 0;
    private initialized: boolean = false;
    private onUpdate: ((rsi: number, meta: RSIMetadata) => void) | null = null;

    constructor(options: RSIOptions = {}) {
        this.period = options.period || 14;
        this.onUpdate = options.onUpdate || null;
    }

    /**
     * Calculate RSI from an array of prices
     */
    public calculate(prices: number[]): number[] {
        if (prices.length < 2) {
            return [];
        }

        const rsiValues: number[] = [];

        for (let i = 1; i < prices.length; i++) {
            const result = this.addPrice(prices[i], prices[i - 1]);
            if (result !== null) {
                rsiValues.push(result.rsi);
            }
        }

        return rsiValues;
    }

    /**
     * Add a single price and get RSI update
     */
    public addPrice(price: number, previousPrice: number): RSICalculationResult | null {
        const delta = price - previousPrice;

        if (delta > 0) {
            this.gains.push(delta);
            this.losses.push(0);
        } else {
            this.gains.push(0);
            this.losses.push(-delta);
        }

        if (this.gains.length > this.period) {
            this.gains.shift();
            this.losses.shift();
        }

        if (this.gains.length === this.period) {
            if (!this.initialized) {
                this.avgGain = this.gains.reduce((a, b) => a + b, 0) / this.period;
                this.avgLoss = this.losses.reduce((a, b) => a + b, 0) / this.period;
                this.initialized = true;
            } else {
                const lastGain = this.gains[this.gains.length - 1];
                const lastLoss = this.losses[this.losses.length - 1];

                this.avgGain = ((this.avgGain * (this.period - 1)) + lastGain) / this.period;
                this.avgLoss = ((this.avgLoss * (this.period - 1)) + lastLoss) / this.period;
            }

            const rs = this.avgLoss > 0 ? (this.avgGain / this.avgLoss) : Infinity;
            const rsi = rs === Infinity ? 100 : 100 - (100 / (1 + rs));

            const metadata: RSIMetadata = {
                avgGain: this.avgGain,
                avgLoss: this.avgLoss,
                period: this.period,
                price: price,
                timestamp: Date.now()
            };

            if (this.onUpdate) {
                this.onUpdate(rsi, metadata);
            }

            return { rsi, metadata };
        }

        return null;
    }

    /**
     * Get current state without updating
     */
    public getState(): { avgGain: number; avgLoss: number; initialized: boolean } {
        return {
            avgGain: this.avgGain,
            avgLoss: this.avgLoss,
            initialized: this.initialized
        };
    }

    /**
     * Reset the calculator state
     */
    public reset(): void {
        this.gains = [];
        this.losses = [];
        this.avgGain = 0;
        this.avgLoss = 0;
        this.initialized = false;
    }
}

