package main

import "math"

// RSI struct maintains state for RSI calculation
type RSI struct {
    period     int
    gains      []float64
    losses     []float64
    avgGain    float64
    avgLoss    float64
    initialized bool
}

// NewRSI creates a new RSI instance with the specified period
func NewRSI(period int) *RSI {
    return &RSI{
        period:     period,
        gains:      make([]float64, 0, period),
        losses:     make([]float64, 0, period),
        avgGain:    0.0,
        avgLoss:    0.0,
        initialized: false,
    }
}

// Calculate processes price data and returns RSI values
func (r *RSI) Calculate(prices []float64) []float64 {
    if len(prices) < 2 {
        return []float64{}
    }

    rsiValues := make([]float64, 0, len(prices))

    for i := 1; i < len(prices); i++ {
        delta := prices[i] - prices[i-1]

        if delta > 0 {
            r.gains = append(r.gains, delta)
            r.losses = append(r.losses, 0.0)
        } else {
            r.gains = append(r.gains, 0.0)
            r.losses = append(r.losses, -delta)
        }

        // Maintain sliding window
        if len(r.gains) > r.period {
            r.gains = r.gains[1:]
            r.losses = r.losses[1:]
        }

        if len(r.gains) == r.period {
            if !r.initialized {
                // Initial average using simple mean
                r.avgGain = sum(r.gains) / float64(r.period)
                r.avgLoss = sum(r.losses) / float64(r.period)
                r.initialized = true
            } else {
                // Wilder's smoothing
                lastGain := r.gains[len(r.gains)-1]
                lastLoss := r.losses[len(r.losses)-1]

                r.avgGain = ((r.avgGain * float64(r.period-1)) + lastGain) / float64(r.period)
                r.avgLoss = ((r.avgLoss * float64(r.period-1)) + lastLoss) / float64(r.period)
            }

            // Calculate RS and RSI
            var rs float64
            if r.avgLoss > 0.0 {
                rs = r.avgGain / r.avgLoss
            } else {
                rs = math.Inf(1)
            }

            var rsi float64
            if math.IsInf(rs, 1) {
                rsi = 100.0
            } else {
                rsi = 100.0 - (100.0 / (1.0 + rs))
            }

            rsiValues = append(rsiValues, rsi)
        }
    }

    return rsiValues
}

// Reset clears the RSI state for a new data stream
func (r *RSI) Reset() {
    r.gains = make([]float64, 0, r.period)
    r.losses = make([]float64, 0, r.period)
    r.avgGain = 0.0
    r.avgLoss = 0.0
    r.initialized = false
}

// Helper function to sum float64 slice
func sum(slice []float64) float64 {
    total := 0.0
    for _, v := range slice {
        total += v
    }
    return total
}

