class RSI
  attr_reader :period, :avg_gain, :avg_loss, :initialized

  def initialize(period = 14)
    @period = period
    @gains = []
    @losses = []
    @avg_gain = 0.0
    @avg_loss = 0.0
    @initialized = false
  end

  # Calculate RSI from an array of prices
  # Returns an array of RSI values
  def calculate(prices)
    return [] if prices.nil? || prices.length < 2

    rsi_values = []

    (1...prices.length).each do |i|
      delta = prices[i] - prices[i - 1]

      if delta > 0
        @gains << delta
        @losses << 0.0
      else
        @gains << 0.0
        @losses << -delta
      end

      if @gains.length > @period
        @gains.shift
        @losses.shift
      end

      if @gains.length == @period
        unless @initialized
          @avg_gain = @gains.sum / @period.to_f
          @avg_loss = @losses.sum / @period.to_f
          @initialized = true
        else
          last_gain = @gains.last
          last_loss = @losses.last

          @avg_gain = ((@avg_gain * (@period - 1)) + last_gain) / @period
          @avg_loss = ((@avg_loss * (@period - 1)) + last_loss) / @period
        end

        rs = @avg_loss > 0 ? (@avg_gain / @avg_loss) : Float::INFINITY
        rsi = rs == Float::INFINITY ? 100.0 : 100.0 - (100.0 / (1.0 + rs))

        rsi_values << rsi
      end
    end

    rsi_values
  end

  # Reset the calculator state
  def reset
    @gains = []
    @losses = []
    @avg_gain = 0.0
    @avg_loss = 0.0
    @initialized = false
  end

  # Get current state
  def state
    {
      avg_gain: @avg_gain,
      avg_loss: @avg_loss,
      initialized: @initialized,
      window_size: @gains.length
    }
  end
end

