let truncate_list lst n =
  if List.length lst > n then
    let rec drop count = function
      | [] -> []
      | _ :: tl when count > 0 -> drop (count - 1) tl
      | rest -> rest
    in drop (List.length lst - n) lst
  else lst

let update_state state delta =
  let gain, loss = if delta > 0.0 then (delta, 0.0) else (0.0, -delta) in
  let new_gains = truncate_list (state.gains @ [gain]) state.period in
  let new_losses = truncate_list (state.losses @ [loss]) state.period in

  if List.length new_gains < state.period then
    ({ state with gains = new_gains; losses = new_losses }, None)
  else
    let avg_gain, avg_loss, initialized =
      if not state.initialized then
        let avg_gain' = List.fold_left (+.) 0.0 new_gains /. float_of_int state.period in
        let avg_loss' = List.fold_left (+.) 0.0 new_losses /. float_of_int state.period in
        (avg_gain', avg_loss', true)
      else
        let last_gain = List.hd (List.rev new_gains) in
        let last_loss = List.hd (List.rev new_losses) in
        let p = float_of_int state.period in
        let avg_gain' = ((state.avg_gain *. (p -. 1.0)) +. last_gain) /. p in
        let avg_loss' = ((state.avg_loss *. (p -. 1.0)) +. last_loss) /. p in
        (avg_gain', avg_loss', true)
    in
    let rs = if avg_loss > 0.0 then avg_gain /. avg_loss else infinity in
    let rsi = if rs = infinity then 100.0 else 100.0 -. (100.0 /. (1.0 +. rs)) in
    let new_state = {
      gains = new_gains;
      losses = new_losses;
      avg_gain = avg_gain;
      avg_loss = avg_loss;
      initialized = initialized;
      period = state.period;
    } in
    (new_state, Some rsi)

let calculate prices period =
  let rec loop prices state acc =
    match prices with
    | [] -> List.rev acc
    | _ :: [] -> List.rev acc
    | p1 :: p2 :: rest ->
        let delta = p2 -. p1 in
        let new_state, rsi_opt = update_state state delta in
        let new_acc = match rsi_opt with Some v -> v :: acc | None -> acc in
        loop (p2 :: rest) new_state new_acc
  in
  loop prices (create_state period) []

