/// RSI Implementation in Swift for iOS/macOS trading apps
struct RSI {
    private let period: Int
    private var gains: [Double]
    private var losses: [Double]
    private var avgGain: Double
    private var avgLoss: Double
    private var initialized: Bool

    /// Create a new RSI instance
    init(period: Int = 14) {
        self.period = period
        self.gains = []
        self.losses = []
        self.avgGain = 0.0
        self.avgLoss = 0.0
        self.initialized = false
    }

    /// Calculate RSI from an array of prices
    mutating func calculate(_ prices: [Double]) -> [Double] {
        guard prices.count >= 2 else { return [] }

        var rsiValues: [Double] = []
        rsiValues.reserveCapacity(prices.count)

        for i in 1..<prices.count {
            let delta = prices[i] - prices[i - 1]

            if delta > 0 {
                gains.append(delta)
                losses.append(0.0)
            } else {
                gains.append(0.0)
                losses.append(-delta)
            }

            if gains.count > period {
                gains.removeFirst()
                losses.removeFirst()
            }

            if gains.count == period {
                if !initialized {
                    avgGain = gains.reduce(0, +) / Double(period)
                    avgLoss = losses.reduce(0, +) / Double(period)
                    initialized = true
                } else {
                    let lastGain = gains.last ?? 0
                    let lastLoss = losses.last ?? 0

                    avgGain = ((avgGain * Double(period - 1)) + lastGain) / Double(period)
                    avgLoss = ((avgLoss * Double(period - 1)) + lastLoss) / Double(period)
                }

                let rs = avgLoss > 0 ? (avgGain / avgLoss) : .infinity
                let rsi = rs.isInfinite ? 100.0 : 100.0 - (100.0 / (1.0 + rs))

                rsiValues.append(rsi)
            }
        }

        return rsiValues
    }

    /// Reset the calculator state
    mutating func reset() {
        gains.removeAll()
        losses.removeAll()
        avgGain = 0.0
        avgLoss = 0.0
        initialized = false
    }

    /// Get current state
    func getState() -> (avgGain: Double, avgLoss: Double, initialized: Bool, windowSize: Int) {
        return (avgGain, avgLoss, initialized, gains.count)
    }
}

