        error('Prices vector must contain at least 2 elements');
    end

    % Calculate price differences
    deltas = diff(prices);

    % Calculate gains and losses
    gains = max(deltas, 0);
    losses = max(-deltas, 0);

    % Pre-allocate arrays
    n = length(gains);
    avg_gain = zeros(1, n);
    avg_loss = zeros(1, n);
    rsi_values = zeros(1, n - period + 1);

    % Initial averages (first period)
    if n >= period
        avg_gain(period) = mean(gains(1:period));
        avg_loss(period) = mean(losses(1:period));

        % Wilder's smoothing for remaining periods
        for i = (period + 1):n
            avg_gain(i) = ((avg_gain(i - 1) * (period - 1)) + gains(i)) / period;
            avg_loss(i) = ((avg_loss(i - 1) * (period - 1)) + losses(i)) / period;
        end

        % Calculate RSI
        for i = period:n
            if avg_loss(i) > 0
                rs = avg_gain(i) / avg_loss(i);
                rsi_values(i - period + 1) = 100 - (100 / (1 + rs));
            else
                rsi_values(i - period + 1) = 100;
            end
        end
    end
end

