// RSI State structure
pub const RSIState = struct {
    period: usize,
    gains: std.ArrayList(f64),
    losses: std.ArrayList(f64),
    avg_gain: f64,
    avg_loss: f64,
    initialized: bool,

    pub fn init(allocator: Allocator, period: usize) !RSIState {
        return RSIState{
            .period = period,
            .gains = try std.ArrayList(f64).initCapacity(allocator, period),
            .losses = try std.ArrayList(f64).initCapacity(allocator, period),
            .avg_gain = 0.0,
            .avg_loss = 0.0,
            .initialized = false,
        };
    }

    pub fn deinit(self: *RSIState) void {
        self.gains.deinit();
        self.losses.deinit();
    }

    pub fn reset(self: *RSIState) void {
        self.gains.clearRetainingCapacity();
        self.losses.clearRetainingCapacity();
        self.avg_gain = 0.0;
        self.avg_loss = 0.0;
        self.initialized = false;
    }

    pub fn update(self: *RSIState, delta: f64) ?f64 {
        const gain = if (delta > 0.0) delta else 0.0;
        const loss = if (delta > 0.0) 0.0 else -delta;

        try(self.gains.append(gain));
        try(self.losses.append(loss));

        if (self.gains.items.len > self.period) {
            _ = self.gains.orderedRemove(0);
            _ = self.losses.orderedRemove(0);
        }

        if (self.gains.items.len < self.period) {
            return null;
        }

        // Calculate averages
        if (!self.initialized) {
            self.avg_gain = sumSlice(self.gains.items) / @as(f64, @floatFromInt(self.period));
            self.avg_loss = sumSlice(self.losses.items) / @as(f64, @floatFromInt(self.period));
            self.initialized = true;
        } else {
            const last_gain = self.gains.items[self.gains.items.len - 1];
            const last_loss = self.losses.items[self.losses.items.len - 1];
            const p = @as(f64, @floatFromInt(self.period));

            self.avg_gain = ((self.avg_gain * (p - 1.0)) + last_gain) / p;
            self.avg_loss = ((self.avg_loss * (p - 1.0)) + last_loss) / p;
        }

        // Calculate RSI
        const rs = if (self.avg_loss > 0.0) self.avg_gain / self.avg_loss else math.inf(f64);
        const rsi = if (math.isInf(rs)) 100.0 else 100.0 - (100.0 / (1.0 + rs));

        return rsi;
    }

    fn sumSlice(slice: []f64) f64 {
        var sum: f64 = 0.0;
        for (slice) |v| {
            sum += v;
        }
        return sum;
    }
};

// Functional RSI calculation with allocator
pub fn calculateRSI(allocator: Allocator, prices: []f64, period: usize) ![]f64 {
    if (prices.len < 2) {
        return try allocator.alloc(f64, 0);
    }

    var state = try RSIState.init(allocator, period);
    defer state.deinit();

    var rsi_values = try std.ArrayList(f64).initCapacity(allocator, prices.len);
    defer rsi_values.deinit();

    for (1..prices.len) |i| {
        const delta = prices[i] - prices[i - 1];
        if (state.update(delta)) |rsi| {
            try rsi_values.append(rsi);
        }
    }

    return try rsi_values.toOwnedSlice();
}

// Arena-based memory management for performance
pub fn calculateRSIArena(arena: *std.heap.ArenaAllocator, prices: []f64, period: usize) ![]f64 {
    const allocator = arena.allocator();

