using System;
using System.Collections.Generic;
using System.Linq;

namespace OfflinePixel.RSI
{
    /// <summary>
    /// RSI Implementation in C# for .NET Enterprise
    /// </summary>
    public class RSICalculator
    {
        private readonly int _period;
        private readonly Queue<double> _gains;
        private readonly Queue<double> _losses;
        private double _avgGain;
        private double _avgLoss;
        private bool _initialized;

        public RSICalculator(int period = 14)
        {
            _period = period;
            _gains = new Queue<double>(period);
            _losses = new Queue<double>(period);
            _avgGain = 0.0;
            _avgLoss = 0.0;
            _initialized = false;
        }

        public List<double> Calculate(double[] prices)
        {
            if (prices == null || prices.Length < 2)
                return new List<double>();

            var rsiValues = new List<double>(prices.Length);

            for (int i = 1; i < prices.Length; i++)
            {
                double delta = prices[i] - prices[i - 1];

                if (delta > 0.0)
                {
                    _gains.Enqueue(delta);
                    _losses.Enqueue(0.0);
                }
                else
                {
                    _gains.Enqueue(0.0);
                    _losses.Enqueue(-delta);
                }

                if (_gains.Count > _period)
                {
                    _gains.Dequeue();
                    _losses.Dequeue();
                }

                if (_gains.Count == _period)
                {
                    if (!_initialized)
                    {
                        _avgGain = _gains.Average();
                        _avgLoss = _losses.Average();
                        _initialized = true;
                    }
                    else
                    {
                        double lastGain = _gains.Last();
                        double lastLoss = _losses.Last();

                        _avgGain = ((_avgGain * (_period - 1)) + lastGain) / _period;
                        _avgLoss = ((_avgLoss * (_period - 1)) + lastLoss) / _period;
                    }

                    double rs = (_avgLoss > 0.0) ? (_avgGain / _avgLoss) : double.PositiveInfinity;
                    double rsi = double.IsInfinity(rs) ? 100.0 : 100.0 - (100.0 / (1.0 + rs));

                    rsiValues.Add(rsi);
                }
            }

            return rsiValues;
        }

        public void Reset()
        {
            _gains.Clear();
            _losses.Clear();
            _avgGain = 0.0;
            _avgLoss = 0.0;
            _initialized = false;
        }

        public (double AvgGain, double AvgLoss, bool Initialized, int WindowSize) GetState()
        {
            return (_avgGain, _avgLoss, _initialized, _gains.Count);
        }
    }

    /// <summary>
    /// LINQ Extension Methods
    /// </summary>
    public static class RSIExtensions
    {
        public static List<double> CalculateRSI(this IEnumerable<double> prices, int period = 14)
        {
            var calculator = new RSICalculator(period);
            return calculator.Calculate(prices.ToArray());
        }
    }
}

