module RSI.FSharp

open System
open System.Collections.Generic

/// Immutable RSI state (functional style)
type RSIState = {
    Period: int
    Gains: Queue<double>
    Losses: Queue<double>
    AvgGain: float
    AvgLoss: float
    Initialized: bool
}

/// Create initial RSI state
let createState period =
    {
        Period = period
        Gains = new Queue<double>(period)
        Losses = new Queue<double>(period)
        AvgGain = 0.0
        AvgLoss = 0.0
        Initialized = false
    }

/// Update state with price delta
let updateState state delta =
    let (gain, loss) = if delta > 0.0 then (delta, 0.0) else (0.0, -delta)

    state.Gains.Enqueue(gain)
    state.Losses.Enqueue(loss)

    if state.Gains.Count > state.Period then
        state.Gains.Dequeue() |> ignore
        state.Losses.Dequeue() |> ignore

    if state.Gains.Count < state.Period then
        state, None
    else
        let avgGain, avgLoss, initialized =
            if not state.Initialized then
                let avgG = state.Gains.Average()
                let avgL = state.Losses.Average()
                avgG, avgL, true
            else
                let lastGain = state.Gains.Last()
                let lastLoss = state.Losses.Last()
                let p = float state.Period
                let avgG = ((state.AvgGain * (p - 1.0)) + lastGain) / p
                let avgL = ((state.AvgLoss * (p - 1.0)) + lastLoss) / p
                avgG, avgL, true

        let rs = if avgLoss > 0.0 then avgGain / avgLoss else Double.PositiveInfinity
        let rsi = if Double.IsInfinity(rs) then 100.0 else 100.0 - (100.0 / (1.0 + rs))

        let newState = {
            state with
                AvgGain = avgGain
                AvgLoss = avgLoss
                Initialized = initialized
        }

        newState, Some rsi

/// Calculate RSI from prices using functional fold
let calculateRSI prices period =
    let initialState = createState period
    let _, rsiValues =
        prices
        |> Array.pairwise
        |> Array.map (fun (prev, curr) -> curr - prev)
        |> Array.fold (fun (state, acc) delta ->
            let newState, rsiOpt = updateState state delta
            let newAcc = match rsiOpt with Some v -> List.append acc [v] | None -> acc
            newState, newAcc
        ) (initialState, [])
    rsiValues

